import{_ as o,o as l,c as a,a4 as i}from"./chunks/framework.ChErgFjV.js";const p=JSON.parse('{"title":"《解剖人性1000条（第1部）》读书笔记","description":"","frontmatter":{},"headers":[],"relativePath":"study/reading-notes/20260711-《解剖人性1000条》读书笔记.md","filePath":"study/reading-notes/20260711-《解剖人性1000条》读书笔记.md","lastUpdated":1783903885000}'),r={name:"study/reading-notes/20260711-《解剖人性1000条》读书笔记.md"};function u(e,t,d,q,h,n){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="《解剖人性1000条-第1部-》读书笔记" tabindex="-1">《解剖人性1000条（第1部）》读书笔记 <a class="header-anchor" href="#《解剖人性1000条-第1部-》读书笔记" aria-label="Permalink to &quot;《解剖人性1000条（第1部）》读书笔记&quot;">​</a></h1><blockquote><p>📅 阅读日期：2026-07-11 📖 书名：解剖人性1000条（第1部） ✍️ 作者：佚名（网络付费电子书） 📄 页数：125页 / 8.7万字 / 1000条</p></blockquote><hr><h2 id="📌-核心观点" tabindex="-1">📌 核心观点 <a class="header-anchor" href="#📌-核心观点" aria-label="Permalink to &quot;📌 核心观点&quot;">​</a></h2><p>全书1000条，围绕六大主题展开，核心可归纳为：</p><h3 id="一、财富思维-穷人打猎-富人农耕" tabindex="-1">一、财富思维：穷人打猎，富人农耕 <a class="header-anchor" href="#一、财富思维-穷人打猎-富人农耕" aria-label="Permalink to &quot;一、财富思维：穷人打猎，富人农耕&quot;">​</a></h3><ul><li>穷人是&quot;打猎思维&quot;——想一夜暴富、零成本赚大钱；富人是&quot;农耕思维&quot;——春种夏长秋收冬藏，需要建设和培育周期（#171）</li><li>赚钱的本质是<strong>认知的变现</strong>（#213），不是勤奋的变现。大部分人看似努力，实则低效（#44/116）</li><li>老板只需要做两件事：<strong>思考+决策</strong>（#115/283/369）。亲力亲为是打工者思维，忙到没时间思考是最危险的（#22/295/370）</li><li>500万以下不要研究理财，只研究如何赚钱（#138/309）。老百姓理财就两个结果：要么理少了，要么理没了（#988）</li><li><strong>护城河</strong>决定生意能做多久，没有护城河的快速赚钱窗口期极短（#35）</li></ul><h3 id="二、人性规律-权力与利益的底层逻辑" tabindex="-1">二、人性规律：权力与利益的底层逻辑 <a class="header-anchor" href="#二、人性规律-权力与利益的底层逻辑" aria-label="Permalink to &quot;二、人性规律：权力与利益的底层逻辑&quot;">​</a></h3><ul><li>大领导都是&quot;人性艺术家&quot;，没有绝对的清廉也没有绝对的大贪，能往上走的都懂得拿大不拿小、拿强不拿弱（#2-3）</li><li>层次越高的圈子攻击性越弱，底层人人带攻击性，互相踩踏（#7/33）</li><li>人只相信比自己强的人。不要听普通人的意见，如果普通人的意见有用，他就不会过普通人的生活（#365）</li><li><strong>承认别人优秀是最难的</strong>（#79），但这是成长的前提。凤凰男最难转过来的思维就是承认别人比咱优秀、愿意臣服学习（#952）</li></ul><h3 id="三、商业本质-产品为王-模式为辅" tabindex="-1">三、商业本质：产品为王，模式为辅 <a class="header-anchor" href="#三、商业本质-产品为王-模式为辅" aria-label="Permalink to &quot;三、商业本质：产品为王，模式为辅&quot;">​</a></h3><ul><li>商业终究回归本质：品牌商在卖，消费者在买，无中间商（#158）</li><li>产品才是买卖生意中的根本（#256），不要迷恋商业模式（#155）</li><li>做有钱人的生意——他们不仅让你赚得开心，还会感激你（#5/65/297）</li><li>选品比运营重要10倍（#515），90%决定于选品</li><li>小而美、聚焦单品比大而全更抗风险（#93-97）</li></ul><h3 id="四、互联网杠杆-最大的杠杆是影响力" tabindex="-1">四、互联网杠杆：最大的杠杆是影响力 <a class="header-anchor" href="#四、互联网杠杆-最大的杠杆是影响力" aria-label="Permalink to &quot;四、互联网杠杆：最大的杠杆是影响力&quot;">​</a></h3><ul><li>互联网是今天最大的杠杆（#336/525），不用杠杆就会被别人指数级落伍</li><li>影响力怎么打造：选适合自己的输出方式+输出领域，然后<strong>坚持</strong>（#482/488）</li><li>互联网经济特点：<strong>十年钱一年赚</strong>，前面是基础，爆发时一年回本（#441/511）</li><li>保持高频输出就一定能俘获关注，前提是前期没人关注时也能坚持（#440/462）</li></ul><h3 id="五、婚姻与关系-价值匹配是核心" tabindex="-1">五、婚姻与关系：价值匹配是核心 <a class="header-anchor" href="#五、婚姻与关系-价值匹配是核心" aria-label="Permalink to &quot;五、婚姻与关系：价值匹配是核心&quot;">​</a></h3><ul><li>婚姻本质是利益合约，和爱情没有多大关系（#669），婚姻是两个家族的合作（#632）</li><li>选伴侣看什么：家境、品行、学历、工作、长相——很多人把顺序搞反了（#634）</li><li>情绪稳定是最重要的婚姻属性（#633），情绪不稳定的人不仅消耗时间还消耗能量（#673）</li><li>男人最廉价的就是一无所有时的温柔（#577/596），&quot;对我好&quot;不应该成为择偶标准（#697）</li><li>没有得到父母祝福的婚姻多是悲剧（#566/619）</li></ul><h3 id="六、自我成长-操作系统决定人生高度" tabindex="-1">六、自我成长：操作系统决定人生高度 <a class="header-anchor" href="#六、自我成长-操作系统决定人生高度" aria-label="Permalink to &quot;六、自我成长：操作系统决定人生高度&quot;">​</a></h3><ul><li>不同高度的人，操作系统不同（#318）。从打工者到老板，需要更换操作系统（#373/765）</li><li>人到35岁，核心竞争力从专业技能转向领导力、沟通表达、思维决策（#301）</li><li>人20-30岁变化最大，没蜕变就尘埃落定了（#837）。优秀的人从年轻时就很优秀（#840）</li><li>长线思维拉开差距（#946-947），每天复利式成长，日积月累自然超越（#947）</li><li>保持正向节奏，不要打破一直带来正向收入和成就感的习惯（#867）</li></ul><hr><h2 id="💡-启发思考" tabindex="-1">💡 启发思考 <a class="header-anchor" href="#💡-启发思考" aria-label="Permalink to &quot;💡 启发思考&quot;">​</a></h2><h3 id="对人的启发" tabindex="-1">对人的启发 <a class="header-anchor" href="#对人的启发" aria-label="Permalink to &quot;对人的启发&quot;">​</a></h3><ol><li><strong>&quot;贫穷会限制想象力&quot;</strong>——这句话不只是说穷人想象不到富人的生活，更是说穷人的思维模式会自我循环。打猎思维让人总想速成，越急越容易当韭菜（#198/171）</li><li><strong>&quot;闲聊破财&quot;</strong>——漫无目的社交是最隐蔽的财富消耗。时间花在哪，结果就在哪（#134）</li><li><strong>&quot;免费的是最贵的&quot;</strong>——免费获得的东西背后都有隐形代价，真正的高手都明白这一点（#943）</li><li><strong>焦虑控制在一定尺度是好事</strong>——它带来源源不断的动力（#331），完全没焦虑说明目标不够</li></ol><h3 id="从心理学和社会实践角度的启发-🎯" tabindex="-1">从心理学和社会实践角度的启发 🎯 <a class="header-anchor" href="#从心理学和社会实践角度的启发-🎯" aria-label="Permalink to &quot;从心理学和社会实践角度的启发 🎯&quot;">​</a></h3><h4 id="🌱-人生发展维度" tabindex="-1">🌱 人生发展维度 <a class="header-anchor" href="#🌱-人生发展维度" aria-label="Permalink to &quot;🌱 人生发展维度&quot;">​</a></h4><ol><li><p><strong>&quot;老板只需要思考+决策&quot;的心理突破</strong>：作为带过20+人项目、30+人部门的技术管理者，我深有体会。心理学上的&quot;行动偏好&quot;让我们倾向于忙碌——亲力亲为看似负责，实则是用战术勤奋掩盖战略懒惰</p></li><li><p><strong>&quot;渐冻人思维&quot;的战略意义</strong>：把自己想象成渐冻人——只有思考和决策。这是一个心理学上的认知重构：把&quot;不能做&quot;重构为&quot;不应该做&quot;，把精力集中在不可替代的思考和决策上</p></li><li><p><strong>&quot;人到35岁核心竞争力转向&quot;的转型焦虑</strong>：心理学研究表明，中年危机往往源于&quot;身份认同&quot;的转变——从&quot;我做什么&quot;转向&quot;我是谁&quot;。专业技能只是入场券，真正的壁垒在于影响力、人脉和决策力</p></li></ol><h4 id="🏠-家庭关系维度" tabindex="-1">🏠 家庭关系维度 <a class="header-anchor" href="#🏠-家庭关系维度" aria-label="Permalink to &quot;🏠 家庭关系维度&quot;">​</a></h4><ol><li><p><strong>&quot;家庭教育90%是生活方式&quot;的启示</strong>：大人读书做事，孩子耳濡目染。心理学上的&quot;榜样效应&quot;比说教更有效——孩子看到的父亲行为比听到的父亲言语更重要</p></li><li><p><strong>维护父亲权威的心理意义</strong>：配偶间的分歧不要在孩子面前暴露。心理学研究表明，父母一致性是孩子安全感的重要来源</p></li><li><p><strong>避免&quot;匮乏感&quot;的心理创伤</strong>：给孩子好的体验不是溺爱，而是避免&quot;匮乏感&quot;带来的脆弱和过度自尊——这会影响孩子一生的心理健康</p></li></ol><h4 id="💼-事业发展维度" tabindex="-1">💼 事业发展维度 <a class="header-anchor" href="#💼-事业发展维度" aria-label="Permalink to &quot;💼 事业发展维度&quot;">​</a></h4><ol><li><p><strong>&quot;执行者思维&quot;到&quot;思考+决策模式&quot;的转型</strong>：每天留出2小时不被打扰的&quot;渐冻人时间&quot;，专注思考和输出。这是从打工者操作系统到老板操作系统的核心转变</p></li><li><p><strong>&quot;互联网是最大的杠杆&quot;的实践意义</strong>：选择适合自己的输出方式+输出领域，然后坚持。影响力是今天最大的资产</p></li><li><p><strong>&quot;十年钱一年赚&quot;的长期思维</strong>：互联网经济特点是前面是基础，爆发时一年回本。心理学上的&quot;延迟满足&quot;能力是成功的关键预测因子</p></li></ol><h4 id="📚-小孩子教育维度" tabindex="-1">📚 小孩子教育维度 <a class="header-anchor" href="#📚-小孩子教育维度" aria-label="Permalink to &quot;📚 小孩子教育维度&quot;">​</a></h4><ol><li><p><strong>&quot;生活方式熏陶&quot;胜过&quot;刻意启蒙&quot;</strong>：家庭教育90%是生活方式，10%是刻意启蒙。孩子看到的父亲在工作、学习、思考，这比任何培训班都有效</p></li><li><p><strong>&quot;避免匮乏感&quot;的教育智慧</strong>：给孩子好的体验不是溺爱，而是建立心理安全感。匮乏感会带来终身的心理创伤</p></li><li><p><strong>&quot;承认别人优秀&quot;的成长心态</strong>：心理学上的&quot;成长型思维&quot;——承认别人优秀是最难的，但这是成长的前提</p></li></ol><hr><h2 id="🎯-三、以我的背景给的建议" tabindex="-1">🎯 三、以我的背景给的建议 <a class="header-anchor" href="#🎯-三、以我的背景给的建议" aria-label="Permalink to &quot;🎯 三、以我的背景给的建议&quot;">​</a></h2><h3 id="背景-17年开发-技术管理-两个孩子父亲-精力下降想转型" tabindex="-1">背景：17年开发+技术管理，两个孩子父亲，精力下降想转型 <a class="header-anchor" href="#背景-17年开发-技术管理-两个孩子父亲-精力下降想转型" aria-label="Permalink to &quot;背景：17年开发+技术管理，两个孩子父亲，精力下降想转型&quot;">​</a></h3><h4 id="🌱-人生发展建议" tabindex="-1">🌱 人生发展建议 <a class="header-anchor" href="#🌱-人生发展建议" aria-label="Permalink to &quot;🌱 人生发展建议&quot;">​</a></h4><p><strong>建议一：从&quot;执行者思维&quot;切换到&quot;思考+决策模式&quot; 🔴🔴🔴</strong></p><p>心理学上的&quot;行动偏好&quot;让我们用忙碌来缓解焦虑。但书中说：老板只需要思考+决策。</p><ul><li>给日常琐事标价：哪些事可以花100-200元/小时外包？</li><li>每天留出2小时不被打扰的&quot;渐冻人时间&quot;，专注思考和输出</li><li>用&quot;这件事与我有关吗？能来钱吗？&quot;过滤99%的无效信息</li></ul><p><strong>建议二：建立&quot;长线思维&quot;的心理习惯 🔴🔴</strong></p><p>心理学研究表明，能延迟满足的人成功率更高。书中说：十年钱一年赚。</p><ul><li>前面是基础，爆发时一年回本</li><li>保持正向节奏，不要打破一直带来正向收入和成就感的习惯</li><li>每天复利式成长，日积月累自然超越</li></ul><p><strong>建议三：警惕&quot;路径依赖&quot;的心理陷阱 🔴</strong></p><p>心理学上的&quot;现状偏差&quot;让我们停留在舒适区。但人到35岁，核心竞争力从专业技能转向领导力、沟通表达、思维决策。</p><table tabindex="0"><thead><tr><th>过去核心能力</th><th>未来核心能力</th><th>心理转型</th></tr></thead><tbody><tr><td>专业技能</td><td>领导力</td><td>从&quot;做&quot;到&quot;带&quot;</td></tr><tr><td>执行力</td><td>决策力</td><td>从&quot;怎么做好&quot;到&quot;做什么&quot;</td></tr><tr><td>技术深度</td><td>影响力</td><td>从&quot;深耕&quot;到&quot;传播&quot;</td></tr></tbody></table><h4 id="🏠-家庭关系建议" tabindex="-1">🏠 家庭关系建议 <a class="header-anchor" href="#🏠-家庭关系建议" aria-label="Permalink to &quot;🏠 家庭关系建议&quot;">​</a></h4><p><strong>建议四：维护父亲在孩子心中的权威 🔴🔴</strong></p><p>心理学研究表明，父母一致性是孩子安全感的重要来源：</p><ul><li>配偶间的分歧不要在孩子面前暴露</li><li>父亲形象的一致性比&quot;正确性&quot;更重要</li><li>最愚蠢的妈妈就是总是在孩子面前弱化父亲的形象</li></ul><p><strong>建议五：用&quot;生活方式&quot;教育孩子 🔴🔴</strong></p><p>家庭教育90%是生活方式，10%是刻意启蒙：</p><ul><li>孩子看到的是你做什么，而不是你说什么</li><li>保持阅读、思考、学习的习惯，孩子自然模仿</li><li>不做焦虑型家长，用行动而非焦虑影响孩子</li></ul><h4 id="💼-事业发展建议" tabindex="-1">💼 事业发展建议 <a class="header-anchor" href="#💼-事业发展建议" aria-label="Permalink to &quot;💼 事业发展建议&quot;">​</a></h4><p><strong>建议六：系统经营个人影响力 🔴🔴</strong></p><p>互联网是今天最大的杠杆：</p><ul><li>选定输出领域：你17年技术管理经验是独特资产</li><li>保持高频输出：每天至少一条有价值的内容</li><li>打造&quot;追剧感&quot;：让别人每天不看你更新就觉得少了仪式感</li></ul><p><strong>建议七：团队管理升级 🔴</strong></p><p>心理学上的&quot;制度信任&quot;比&quot;人格信任&quot;更可靠：</p><ul><li>用规则代替忠诚，允许任何人离开</li><li>关键岗位永远要有替补队员</li><li>给钱超出预期是最好的驱动，比团建、画饼都有效</li></ul><h4 id="📚-小孩子教育建议" tabindex="-1">📚 小孩子教育建议 <a class="header-anchor" href="#📚-小孩子教育建议" aria-label="Permalink to &quot;📚 小孩子教育建议&quot;">​</a></h4><p><strong>建议八：避免&quot;匮乏感&quot;的心理创伤 🔴🔴</strong></p><p>心理学研究表明，童年的匮乏感会影响终生：</p><ul><li>给孩子好的体验不是溺爱，而是建立心理安全感</li><li>匮乏感会带来脆弱和过度自尊</li><li>经济条件允许的情况下，不要刻意制造&quot;吃苦&quot;</li></ul><p><strong>建议九：培养&quot;承认别人优秀&quot;的心态 🔴</strong></p><p>心理学上的&quot;成长型思维&quot;：</p><ul><li>凤凰男最难转过来的思维就是承认别人比咱优秀</li><li>承认别人优秀是最难的，但这是成长的前提</li><li>教孩子学会欣赏他人，而非嫉妒或否认</li></ul><hr><h2 id="📋-行动计划" tabindex="-1">📋 行动计划 <a class="header-anchor" href="#📋-行动计划" aria-label="Permalink to &quot;📋 行动计划&quot;">​</a></h2><h3 id="短期-1-3个月" tabindex="-1">短期（1-3个月） <a class="header-anchor" href="#短期-1-3个月" aria-label="Permalink to &quot;短期（1-3个月）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>行动</th><th>状态</th></tr></thead><tbody><tr><td>1</td><td>每天留出2小时&quot;渐冻人时间&quot;专注思考和输出</td><td>⬜</td></tr><tr><td>2</td><td>用&quot;与我有关吗？能来钱吗？&quot;过滤信息流</td><td>⬜</td></tr><tr><td>3</td><td>启动个人品牌的系统性输出（公众号/朋友圈/技术社区）</td><td>⬜</td></tr><tr><td>4</td><td>列出日常琐事清单，标注可外包项及成本</td><td>⬜</td></tr></tbody></table><h3 id="中期-3-12个月" tabindex="-1">中期（3-12个月） <a class="header-anchor" href="#中期-3-12个月" aria-label="Permalink to &quot;中期（3-12个月）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>行动</th><th>状态</th></tr></thead><tbody><tr><td>1</td><td>建立个人品牌影响力：坚持每日输出，积累关注者</td><td>⬜</td></tr><tr><td>2</td><td>团队管理升级：推行量化式管理+关键岗位备胎制</td><td>⬜</td></tr><tr><td>3</td><td>找到1-2位&quot;略高于自己&quot;的导师/圈子，持续靠近学习</td><td>⬜</td></tr><tr><td>4</td><td>用品牌带自己，而非自己带品牌——选择合作平台和背书</td><td>⬜</td></tr></tbody></table><h3 id="长期-1-3年" tabindex="-1">长期（1-3年） <a class="header-anchor" href="#长期-1-3年" aria-label="Permalink to &quot;长期（1-3年）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>行动</th><th>状态</th></tr></thead><tbody><tr><td>1</td><td>从&quot;执行型技术管理者&quot;转型为&quot;思考+决策型领导者&quot;</td><td>⬜</td></tr><tr><td>2</td><td>建立多线程人生：健康/事业/家庭/输出/社交各有节奏</td><td>⬜</td></tr><tr><td>3</td><td>财富积累阶段只研究赚钱，用长线思维做复利</td><td>⬜</td></tr><tr><td>4</td><td>两个孩子的教育以&quot;生活方式熏陶&quot;为主，不做焦虑型家长</td><td>⬜</td></tr></tbody></table><hr><blockquote><p>⚡ 本书金句摘录</p><ul><li>&quot;赚钱的本质是认知的变现。&quot;（#213）</li><li>&quot;老板只需要思考+决策，别的什么都不需要干。&quot;（#283）</li><li>&quot;免费的是最贵的。&quot;（#943）</li><li>&quot;十年钱一年赚，这是一个变加速的游戏。&quot;（#441）</li><li>&quot;不要试图鹤立鸡群，要离开那群鸡。&quot;（#764）</li><li>&quot;赚钱是最好的修行，人会很平静。&quot;（#30）</li><li>&quot;真正的聪明人都在下笨功夫。&quot;（#188）</li><li>&quot;人最值钱的就是大脑，就凭我们性感的大脑。&quot;（#292）</li><li>&quot;普通人要想成功，唯一的可能，就是拥抱时间。&quot;（#136）</li><li>&quot;最愚蠢的妈妈就是总是在孩子面前弱化父亲的形象。&quot;（#944）</li></ul></blockquote>',74)])])}const b=o(r,[["render",u]]);export{p as __pageData,b as default};
